"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([[2483],{9022:e=>{e.exports=JSON.parse('{"lang":"nb","resources":{"landing":{"meta":{"title":"Linguist \u2013 Oversett nettsider privat | Oversetterutvidelse for Chrome og Firefox","description":"Personvernvennlig oversetterutvidelse for Chrome og Firefox. Oversett nettsider, markert tekst, undertekster og meldinger umiddelbart. Fungerer frakoblet og st\xf8tter integrasjon av oversettelsestjenester og API-er."},"navigation":{"features":{"content":"Funksjoner"},"blog":{"content":"Blogg"},"docs":{"content":"Dokumentasjon"},"github":{"content":"GitHub"}},"install":{"chrome":"Installer for Chrome","firefox":"Installer for Firefox"},"sections":{"hero":{"title":"Oversett nettsider s\xf8ml\xf8st","description":"Linguist er en fleksibel oversetter for nettleseren, drevet av de mest popul\xe6re oversettelsestjenestene.\\n\\nOversett hele nettsider, markert tekst, undertekster p\xe5 Netflix eller i videosamtaler, og private meldinger. Lytt til oversettelser og lagre de viktigste i din personlige ordbok for \xe5 l\xe6re nye ord, selv uten nettilgang.\\n\\nLinguist er et moderne og personvernvennlig alternativ til Google Translate sine nettleserutvidelser. Pr\xf8v det gratis."},"opensource":{"title":"\xc5pen kildekode","content":"Linguist er en gratis nettleserutvidelse med <0>\xe5pen kildekode</0>. Den verken samler inn eller selger brukerdata.\\n\\nDu kan <1>donere</1> for \xe5 st\xf8tte Linguist og hjelpe oss med \xe5 opprettholde uavhengighet og h\xf8y kvalitet.\\n\\nDel gjerne Linguist p\xe5 sosiale medier for \xe5 hjelpe andre med \xe5 oppdage den."},"support":{"title":"Support","content":"Hvis du har sp\xf8rsm\xe5l, kan du kontakte oss <0/>.\\nHvis du har funnet en feil og har en GitHub-konto, ber vi deg <1>opprette en sak</1>."},"createdBy":{"content":"Laget av <0/>."}},"features":{"title":"Funksjoner","items":{"offlineTranslation":{"title":"Frakoblet oversettelse og personvern","content":"Oversett tekst direkte p\xe5 enheten din med den innebygde frakoblede oversetteren. Teksten din forblir privat og sendes ikke over internett.\\n\\nAktiver denne funksjonen i innstillingene for \xe5 holde oversettelser private n\xe5r du jobber med e-poster, dokumenter eller personlige meldinger.\\n\\nDen frakoblede oversetteren lar deg ogs\xe5 oversette nettsider uten nettilgang, noe som er spesielt nyttig n\xe5r du er p\xe5 reise."},"fullPageTranslation":{"title":"Oversett hele nettsider","content":"Rask oversettelse av hele nettsider med h\xf8y kvalitet p\xe5 bare noen f\xe5 klikk.\\n\\nBruk en hurtigtast for \xe5 oversette umiddelbart. Hold musepekeren over den oversatte teksten for \xe5 se originalen. Du kan til og med oversette lukkede sider bak innlogging eller betalingsmurer.\\n\\nSett opp regler for automatisk oversettelse basert p\xe5 sidens spr\xe5k eller domene.\\n\\nLinguist gj\xf8r minimale endringer p\xe5 nettsiden: utvidelsen endrer kun selve teksten, slik at sidens oppsett og brukeropplevelse bevares.\\n\\nAktiver sanntidsoversettelse for flerspr\xe5klige m\xf8ter p\xe5 Zoom, Google Meet og Microsoft Teams."},"selectedTextTranslation":{"title":"Oversett markert tekst p\xe5 hvilken som helst nettside","content":"St\xf8ter du p\xe5 ukjente ord mens du leser en artikkel p\xe5 nett?\\nMarker teksten p\xe5 siden og klikk p\xe5 oversett-knappen.\\n\\nLytt til b\xe5de originalteksten og oversettelsen, og lagre oversettelser i ordboken din for \xe5 se over dem senere."},"textTranslation":{"title":"Rask tekstoversettelse","content":"Trenger du \xe5 oversette noe raskt? Klikk p\xe5 Linguist-ikonet og skriv inn teksten din.\\n\\nDu trenger ikke \xe5 bytte mellom faner eller \xe5pne egne nettsider for oversettelse. Oversett direkte i nettleseren med den tjenesten du foretrekker."},"knowledgeBase":{"title":"Bygg din personlige kunnskapsbase","content":"Hver oversettelse lagres i historikken din, og du kan legge til viktige ord og uttrykk i din personlige ordbok. S\xf8k i ordboken og oversettelseshistorikken n\xe5r som helst.\\n\\nIngenting g\xe5r tapt, selv under lange \xf8kter med research eller l\xe6ring.\\n\\nOrdboken fungerer uten nettilgang, noe som gj\xf8r Linguist ideell for de som l\xe6rer spr\xe5k og reisende som trenger konstant tilgang til ordlistene sine."},"customTranslators":{"title":"Integrer oversettelsestjenester og API-er","content":"Linguist lar deg velge hvilken oversettelsestjeneste du vil bruke.\\n\\nUtvidelsen st\xf8tter popul\xe6re leverand\xf8rer som Google, Yandex og Microsoft, med over 100 tilgjengelige spr\xe5k.\\n\\nHvis en tjeneste du trenger ikke er inkludert, kan du legge den til som en <0>egendefinert oversetter</0>.\\n\\nEgendefinerte oversettere lar deg integrere ethvert oversettelsessystem \u2013 fra moderne LLM-tjenester som ChatGPT, DeepL, DeepSeek og Gemini, til lokale oversettere som kj\xf8rer p\xe5 enheten din, for eksempel Ollama eller LibreTranslate."}}},"faq":{"title":"FAQ","items":{"whatIsLinguist":{"title":"Hva er Linguist?","content":"Linguist er en personvernvennlig oversetterutvidelse for Chrome og Firefox.\\n\\nDen lar deg oversette hele nettsider, markert tekst, undertekster og meldinger direkte i nettleseren, uten at du m\xe5 bytte til eksterne nettsider for oversettelse."},"whyLinguist":{"title":"Hvorfor bruke Linguist?","content":"Det finnes mange nettleserutvidelser som oversetter nettsider, og noen nettlesere har til og med innebygde oversettere. S\xe5 hvorfor bruke Linguist?\\n\\nDe fleste innebygde oversettere og utvidelser har begrenset fleksibilitet. Mange er avhengige av \xe9n enkelt leverand\xf8r, som Google Translate eller Microsoft Bing, mens Firefox tilbyr sin egen frakoblede oversetter. I de fleste tilfeller kan du ikke velge den tjenesten som passer best for dine behov.\\n\\nHvis oversettelseskvaliteten ikke er god nok for ditt bruk, eller hvis det er uaktuelt \xe5 sende privat tekst til tredjepartstjenester, st\xe5r du ofte igjen uten gode alternativer.\\n\\nMange verkt\xf8y fokuserer ogs\xe5 p\xe5 kun \xe9n oppgave. Noen oversetter hele sider, mens andre kun oversetter markert tekst.\\n\\nSamtidig er en del oversetterutvidelser bygget prim\xe6rt for inntjening. Funksjoner som oversettelseshistorikk eller personlige ordb\xf8ker kan kreve et abonnement, og noen ganger blir selv grunnleggende funksjoner som m\xf8rkt tema behandlet som premiumvalg.\\n\\nLinguist har en annen tiln\xe6rming. Utvidelsen er designet som et praktisk verkt\xf8y for oversettelse. Du kan velge den oversettelsestjenesten som fungerer best for deg, bytte mellom leverand\xf8rer, eller legge til dine egne egendefinerte oversettere.\\n\\nLinguist samler ogs\xe5 alt p\xe5 ett sted: oversett hele nettsider, markert tekst, undertekster og meldinger, samtidig som du holder oversikt over viktige oversettelser i historikken og din personlige ordbok."},"theLinguistLogo":{"title":"Hvorfor er Linguist-logoen Babels t\xe5rn?","content":"Linguist-logoen er inspirert av <wiki>Babels t\xe5rn</wiki>, en av de eldste fortellingene om spr\xe5k og kommunikasjon.\\n\\nIf\xf8lge historien snakket menneskene en gang samme spr\xe5k og fors\xf8kte \xe5 bygge et t\xe5rn som n\xe5dde opp til himmelen. T\xe5rnet ble aldri fullf\xf8rt, og menneskeheten ble spredt over mange ulike spr\xe5k. Siden den gang har spr\xe5kforskjeller ofte gjort kommunikasjon vanskeligere.\\n\\nLinguist ble laget for \xe5 bidra til \xe5 l\xf8se dette problemet.\\n\\nBabels t\xe5rn i logoen er en p\xe5minnelse om denne historien: mange spr\xe5k, mange kulturer, og menneskets konstante innsats for \xe5 forst\xe5 hverandre. Linguist bidrar til \xe5 bygge bro over disse avstandene ved \xe5 gj\xf8re oversettelse enkelt, fleksibelt og tilgjengelig direkte i nettleseren din.\\n\\nLogoen gjenspeiler ogs\xe5 \xe5nden i prosjektet. Linguist er ikke bare enda et skall rundt \xabGoogle Translate\xbb. Utvidelsen er bygget av mennesker som bryr seg om spr\xe5k, personvern og \xe5pen teknologi. Babels t\xe5rn representerer nysgjerrighet, l\xe6ring og tanken om at spr\xe5kforskjeller b\xf8r bringe mennesker sammen, ikke holde dem fra hverandre."},"imageTranslation":{"title":"Hvorfor oversetter ikke Linguist tekst i bilder?","content":"Linguist fokuserer p\xe5 p\xe5litelige oversettelsesfunksjoner av h\xf8y kvalitet.\\n\\nVi har unders\xf8kt ulike tiln\xe6rminger for \xe5 oversette tekst i bilder. For \xf8yeblikket gir ikke de fleste tilgjengelige l\xf8sninger konsistente resultater, spesielt ikke n\xe5r de kj\xf8res direkte i nettleseren \u2013 noe som er viktig for \xe5 ivareta brukernes personvern.\\n\\nP\xe5 grunn av dette inkluderer ikke Linguist bildeoversettelse for \xf8yeblikket. Vi foretrekker \xe5 ikke lansere funksjoner som ikke oppfyller v\xe5re kvalitetskrav.\\n\\nHvis vi i fremtiden finner en p\xe5litelig og personvernvennlig m\xe5te \xe5 implementere bildeoversettelse p\xe5, legger vi det gjerne til."},"howTranslatePages":{"title":"Hvordan oversetter Linguist nettsider?","content":"Linguist kan oversette hele nettsider med bare noen f\xe5 klikk. Du kan starte oversettelsen av en side ved \xe5 bruke utvidelsesknappen eller en hurtigtast.\\n\\nOriginalteksten er alltid tilgjengelig. Hold musepekeren over den oversatte teksten for \xe5 se originalen."},"offlineTranslation":{"title":"Kan Linguist oversette sider uten nettilgang?","content":"Ja. Linguist inkluderer en innebygd frakoblet oversetter som lar deg oversette tekst uten \xe5 sende data over internett.\\n\\nDette bidrar til \xe5 beskytte personvernet ditt og lar deg oversette innhold selv uten nettilgang."},"privacy":{"title":"Er Linguist personvernvennlig?","content":"Ja. Linguist er designet med personvern i fokus.\\n\\nUtvidelsen verken samler inn eller selger brukerdata. N\xe5r du bruker den <offline-translator>frakoblede oversetteren</offline-translator>, behandles oversettelsene utelukkende p\xe5 din egen enhet."},"supportedBrowsers":{"title":"Hvilke nettlesere st\xf8tter Linguist?","content":"Linguist er tilgjengelig for Chrome og Firefox. Den fungerer ogs\xe5 i andre Chromium-baserte nettlesere som st\xf8tter Chrome-utvidelser.\\n\\nLinguist fungerer i tillegg i Android-nettlesere som st\xf8tter utvidelser, for eksempel Firefox for Android og enkelte Chromium-baserte nettlesere."},"selectedText":{"title":"Kan Linguist oversette markert tekst?","content":"Ja. Du trenger bare \xe5 markere tekst p\xe5 en hvilken som helst nettside og bruke oversett-knappen for \xe5 oversette den umiddelbart.\\n\\nDu kan ogs\xe5 lytte til oversettelsen og lagre den i din personlige ordbok."},"customTranslators":{"title":"Kan jeg bruke min egen oversettelsestjeneste?","content":"Ja. Linguist st\xf8tter <custom-translator>egendefinerte oversettere</custom-translator>, som lar deg integrere ytterligere oversettelsestjenester.\\n\\nDu kan koble til eksterne API-er eller lokale oversettelsessystemer som <libre-translate>LibreTranslate</libre-translate> eller <ollama>Ollama</ollama>."},"isFree":{"title":"Er Linguist gratis?","content":"Ja. Linguist er helt gratis og har <linguist>\xe5pen kildekode</linguist>.\\n\\nProsjektet st\xf8ttes av fellesskapet, og du kan velge \xe5 <donations>st\xf8tte det med en donasjon</donations>."}}}}},"altVersions":[{"langCode":"ar","langName":"\u0627\u0644\u0639\u0631\u0628\u064a\u0629","url":"https://linguister.io/ar"},{"langCode":"bg","langName":"\u0431\u044a\u043b\u0433\u0430\u0440\u0441\u043a\u0438","url":"https://linguister.io/bg"},{"langCode":"bn","langName":"\u09ac\u09be\u0982\u09b2\u09be","url":"https://linguister.io/bn"},{"langCode":"ca","langName":"catal\xe0","url":"https://linguister.io/ca"},{"langCode":"cs","langName":"\u010de\u0161tina","url":"https://linguister.io/cs"},{"langCode":"da","langName":"dansk","url":"https://linguister.io/da"},{"langCode":"de","langName":"Deutsch","url":"https://linguister.io/de"},{"langCode":"el","langName":"\u0395\u03bb\u03bb\u03b7\u03bd\u03b9\u03ba\u03ac","url":"https://linguister.io/el"},{"langCode":"en","langName":"English","url":"https://linguister.io/"},{"langCode":"es","langName":"espa\xf1ol","url":"https://linguister.io/es"},{"langCode":"fa","langName":"\u0641\u0627\u0631\u0633\u06cc","url":"https://linguister.io/fa"},{"langCode":"fi","langName":"suomi","url":"https://linguister.io/fi"},{"langCode":"fr","langName":"fran\xe7ais","url":"https://linguister.io/fr"},{"langCode":"gu","langName":"\u0a97\u0ac1\u0a9c\u0ab0\u0abe\u0aa4\u0ac0","url":"https://linguister.io/gu"},{"langCode":"he","langName":"\u05e2\u05d1\u05e8\u05d9\u05ea","url":"https://linguister.io/he"},{"langCode":"hi","langName":"\u0939\u093f\u0928\u094d\u0926\u0940","url":"https://linguister.io/hi"},{"langCode":"hu","langName":"magyar","url":"https://linguister.io/hu"},{"langCode":"id","langName":"Indonesia","url":"https://linguister.io/id"},{"langCode":"it","langName":"italiano","url":"https://linguister.io/it"},{"langCode":"ja","langName":"\u65e5\u672c\u8a9e","url":"https://linguister.io/ja"},{"langCode":"jv","langName":"Jawa","url":"https://linguister.io/jv"},{"langCode":"ka","langName":"\u10e5\u10d0\u10e0\u10d7\u10e3\u10da\u10d8","url":"https://linguister.io/ka"},{"langCode":"ko","langName":"\ud55c\uad6d\uc5b4","url":"https://linguister.io/ko"},{"langCode":"mr","langName":"\u092e\u0930\u093e\u0920\u0940","url":"https://linguister.io/mr"},{"langCode":"nb","langName":"norsk bokm\xe5l","url":"https://linguister.io/nb"},{"langCode":"nl","langName":"Nederlands","url":"https://linguister.io/nl"},{"langCode":"pa","langName":"\u0a2a\u0a70\u0a1c\u0a3e\u0a2c\u0a40","url":"https://linguister.io/pa"},{"langCode":"pl","langName":"polski","url":"https://linguister.io/pl"},{"langCode":"pt-BR","langName":"portugu\xeas (Brasil)","url":"https://linguister.io/pt-BR"},{"langCode":"pt-PT","langName":"portugu\xeas europeu","url":"https://linguister.io/pt-PT"},{"langCode":"ro","langName":"rom\xe2n\u0103","url":"https://linguister.io/ro"},{"langCode":"ru","langName":"\u0440\u0443\u0441\u0441\u043a\u0438\u0439","url":"https://linguister.io/ru"},{"langCode":"sl","langName":"sloven\u0161\u010dina","url":"https://linguister.io/sl"},{"langCode":"sr","langName":"\u0441\u0440\u043f\u0441\u043a\u0438","url":"https://linguister.io/sr"},{"langCode":"sv","langName":"svenska","url":"https://linguister.io/sv"},{"langCode":"ta","langName":"\u0ba4\u0bae\u0bbf\u0bb4\u0bcd","url":"https://linguister.io/ta"},{"langCode":"te","langName":"\u0c24\u0c46\u0c32\u0c41\u0c17\u0c41","url":"https://linguister.io/te"},{"langCode":"th","langName":"\u0e44\u0e17\u0e22","url":"https://linguister.io/th"},{"langCode":"tr","langName":"T\xfcrk\xe7e","url":"https://linguister.io/tr"},{"langCode":"uk","langName":"\u0443\u043a\u0440\u0430\u0457\u043d\u0441\u044c\u043a\u0430","url":"https://linguister.io/uk"},{"langCode":"ur","langName":"\u0627\u0631\u062f\u0648","url":"https://linguister.io/ur"},{"langCode":"vi","langName":"Ti\u1ebfng Vi\u1ec7t","url":"https://linguister.io/vi"},{"langCode":"zh-CN","langName":"\u4e2d\u6587\uff08\u4e2d\u56fd\uff09","url":"https://linguister.io/zh-CN"},{"langCode":"zh-TW","langName":"\u4e2d\u6587\uff08\u53f0\u7063\uff09","url":"https://linguister.io/zh-TW"}]}')}}]);